-- Rebuild dependency rows for active versions
DELETE cd
FROM component_dependency cd
INNER JOIN component_version cv ON cv.id = cd.component_version_id
INNER JOIN component c ON c.id = cv.component_id
WHERE c.public_id = UUID_TO_BIN('c6a9e0c8-0407-4a8a-b726-6024a9026288')
  AND cv.version = '1.0.0';

DELETE cd
FROM component_dependency cd
INNER JOIN component_version cv ON cv.id = cd.component_version_id
INNER JOIN component c ON c.id = cv.component_id
WHERE c.public_id = UUID_TO_BIN('9bf9e360-1a53-402d-a7ea-612b947ca293')
  AND cv.version = '1.0.0';

DELETE cd
FROM component_dependency cd
INNER JOIN component_version cv ON cv.id = cd.component_version_id
INNER JOIN component c ON c.id = cv.component_id
WHERE c.public_id = UUID_TO_BIN('2d2dc08d-25a4-43ae-9e7b-afae92788222')
  AND cv.version = '1.0.0';

INSERT INTO component_dependency (
    component_version_id,
    dependency_component_id,
    required,
    type,
    sort_order,
    mount_id,
    path,
    created_at,
    updated_at
) VALUES (
    (
        SELECT cv.id
        FROM component_version cv
